import{_ as a,o as t,c as p,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"几何剑术","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/白刃类/几何剑术.md","filePath":"4.资源分区/6.技艺及称号/武技类/白刃类/几何剑术.md"}'),o={name:"4.资源分区/6.技艺及称号/武技类/白刃类/几何剑术.md"};function b(d,e,l,_,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"几何剑术",tabindex:"-1"},[n("几何剑术 "),r("a",{class:"header-anchor",href:"#几何剑术","aria-label":'Permalink to "几何剑术"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD:灵魂蓝调011")])])],-1),s('<h1 id="几何剑术-1" tabindex="-1">几何剑术 <a class="header-anchor" href="#几何剑术-1" aria-label="Permalink to &quot;几何剑术&quot;">​</a></h1><p>几何剑术<br> 使用几何剑术的前提为至少在学识上具有3级几何学、智力4+、武技3+，并使用迅捷剑为武器才能施展。在获得基础剑术训练和基础步伐训练后，开启后续训练的购买权，无需逐级购买，但需要满足前置条件。</p><p>迅捷剑 25分 武器伤害2L 轻灵 高速1<br> 这种细长的，具有护手和长剑刃的剑曾作为欧洲诸多剑术大师的首选武器，同时也是决斗中的主要兵器。虽然几何剑法所使用的迅捷剑要比其他流派用剑更短一些，但在使用时也会为使用者增加0.6米的触及范围。</p><p>使用几何剑术时，辅助专业从学识-武学掌握变为学识-几何学。</p><p>1000<br> 基础剑术训练<br> 使用几何剑术要求学习者系统性的学习几何学，并将可视圆的基础理论，及分析身体结构，增加触及范围等技战术融入其中。在学习基础剑术训练后，使用迅捷剑进行攻击检定时，可以额外将学识上的附加成功数*1作为检定的增强加值加入检定之中。</p><p>1000<br> 基础步伐训练<br> 始终与敌人拉开交战空间，保持双方在同一可视圆的两端是几何剑法的主要自我防护方式。在学习基础步伐训练后，额外获得2点闪避防御、2点反射豁免检定上的增强加值，并增加5点移动速度。</p><p>D+500<br> 几何剑术：入门<br> 需要：基础剑术训练<br> 现在，你能看到距离你15米及以内的敌人与你之间存在的圆形，一般而言，你和他应该在一个圆的两条切线上，无数个圆占据你和他之间的所有空间。<br> 每轮一次，当符合可视圆条件的敌人移动时，若他的移动距离仍不超过等同于你智力附加成功数*5米（D1C2…S5），则你可以立即向他或远离他移动这些距离直到重新恢复相切线状态，圆的大小将始终不变，若此时不处于自身回合之中，则仍需遵循插入动作规则。如果未能及时响应那次移动以此法进行移动，则可以在那个回合结束时再以此法进行一次移动。</p><p>D+1500<br> 几何剑术：精修<br> 需要：几何剑术：入门<br> 你在每轮中，最多能再额外以此法进行等同于你的智力附加成功*1次移动（D1C2…S5），但每回合至多只能以此法移动一次，并将移动距离额外提升10米。</p><p>C+1000<br> 精修步伐训练<br> 需要：基础步伐训练<br> 当你应用招架以应对一次来自于可视圆范围内敌人进行的攻击时，若其符合可视圆条件，则你在这次攻击中获得免疫接触攻击的效果，若你应用了杂技动作进行这次招架，且你还具有至少2点可以转化为移动动作的AP，则你立即失去2点可以转化为移动动作的AP，并进行一次格挡。现在，可视圆的范围增加到智力属性附加*15米，且现在可视圆可以为此范围内的任意大小。</p><p>B+2000<br> 精修持剑训练<br> 需要：基础剑术训练<br> 几何剑术始终要求使用者持剑状态呈直角，并利用特殊封闭剑技动作和进攻方式尽可能的封锁对手动作，控制对手所持武器。<br> 每轮一次，当你对可视圆范围内的一个敌人进行攻击时，你将忽略对其击落武器的特定部位攻击减值，他也不会获得对应的闪避防御。这次攻击将正常造成伤害，也会附带击落武器的效果，需以正常对抗方式以进行对抗。若你成功以此法击落了被攻击者的武器，则他还会陷入B级创伤来源的迟滞效果中，这个效果将持续存在一轮。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',12)])])}const m=a(o,[["render",b]]);export{f as __pageData,m as default};
